// Parse the agent output to extract issue details
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const exitCode = $input.first().json.exitCode;

// Extract the ACTION REQUIRED section from stdout
const actionSection = stdout.split('ACTION REQUIRED:')[1] || '';

// Count issues from summary line
const issuesMatch = stdout.match(/Issues\s*:\s*(\d+)/);
const issuesCount = issuesMatch ? parseInt(issuesMatch[1]) : 0;

// Extract individual issues
const issueBlocks = [];
const lines = actionSection.split('\n');
let currentIssue = null;

for (const line of lines) {
  const recordMatch = line.match(/\[(\w+)\]\s+(.+)/);
  if (recordMatch) {
    if (currentIssue) issueBlocks.push(currentIssue);
    currentIssue = { record: recordMatch[1], path: recordMatch[2].trim() };
  } else if (currentIssue) {
    const statusMatch = line.match(/Status\s*:\s*(\S+)/);
    const urlMatch    = line.match(/URL\s*:\s*(\S+)/);
    const noteMatch   = line.match(/Note\s*:\s*(.+)/);
    const fieldsMatch = line.match(/Fields\s*:\s*(.+)/);
    if (statusMatch) currentIssue.status = statusMatch[1];
    if (urlMatch)    currentIssue.url    = urlMatch[1];
    if (noteMatch)   currentIssue.note   = noteMatch[1].trim();
    if (fieldsMatch) currentIssue.fields = fieldsMatch[1].trim();
  }
}
if (currentIssue) issueBlocks.push(currentIssue);

return [{
  json: {
    exitCode,
    issuesCount,
    issues: issueBlocks,
    stdout,
    stderr,
    runDate: new Date().toISOString().split('T')[0]
  }
}];

// Build HTML email body from parsed issues
const data = $input.first().json;
const issues = data.issues || [];
const runDate = data.runDate;

const statusColors = {
  '404':         '#dc2626',
  'JS_RENDERED': '#d97706',
  'REDIRECT':    '#2563eb',
  'TIMEOUT':     '#7c3aed',
  'ERROR':       '#dc2626',
};

const actionGuide = {
  '404':         'URL deleted. Find replacement and update annotation_base.json.',
  'JS_RENDERED': 'Page is now JS-rendered. Add or update PDF fallback URL.',
  'REDIRECT':    'URL moved. Update annotation_base.json with the new URL.',
  'TIMEOUT':     'Server slow. Retry manually before taking action.',
  'ERROR':       'Unexpected error. Check URL manually.',
};

let rows = '';
for (const issue of issues) {
  const color  = statusColors[issue.status] || '#374151';
  const action = actionGuide[issue.status]  || 'Check manually.';
  rows += `
    <tr>
      <td style="padding:8px;border:1px solid #e5e7eb;font-weight:bold">${issue.record || ''}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;color:${color};font-weight:bold">${issue.status || ''}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px;color:#6b7280;word-break:break-all">${issue.url || ''}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px">${issue.note || ''}</td>
      <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px;color:#374151">${action}</td>
    </tr>`;
}

const html = `
<html><body style="font-family:Arial,sans-serif;color:#111827;max-width:900px;margin:0 auto">
  <h2 style="color:#dc2626">⚠ TermsIQ URL Agent — Action Required</h2>
  <p><strong>${issues.length} issue(s) detected</strong> during scheduled URL check on ${runDate}.</p>
  <table style="border-collapse:collapse;width:100%;font-size:13px">
    <thead><tr style="background:#f3f4f6">
      <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Record</th>
      <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Status</th>
      <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">URL</th>
      <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Note</th>
      <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Action</th>
    </tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <h3>Next steps</h3>
  <ol>
    <li>Open <code>poc/annotation_base.json</code></li>
    <li>Find the affected record and update the URL or url_status</li>
    <li>Re-run: <code>python poc/url_agent.py --annotation poc/annotation_base.json</code></li>
  </ol>
  <p style="color:#6b7280;font-size:12px">— TermsIQ URL Agent | ${runDate}</p>
</body></html>`;

const plain = `TermsIQ URL Agent — Action Required\n${'='.repeat(50)}\n${issues.length} issue(s) on ${runDate}:\n\n` +
  issues.map(i => `[${i.record}] ${i.status}\n  URL: ${i.url}\n  Note: ${i.note}`).join('\n\n');

return [{ json: { ...data, emailHtml: html, emailPlain: plain } }];

// Log a clean all-OK run to console
const stdout = $input.first().json.stdout || '';
const summaryLine = stdout.split('\n').find(l => l.includes('Issues')) || '';

console.log(`[TermsIQ URL Agent] All OK — ${new Date().toISOString()}`);
console.log(summaryLine.trim());

return [{ json: { status: 'ALL_OK', timestamp: new Date().toISOString() } }];
